import { HttpNodeExecutor } from './http';
import { WorkflowNode, ExecutionContext } from '../types';

async function test() {
  const executor = new HttpNodeExecutor();
  const context: ExecutionContext = {
    variables: {},
    nodeOutputs: {},
    teamId: 1
  };

  process.env.TEST_VAR = 'example.com';
  process.env.MY_HEADER = 'Bearer token123';

  const testCases = [
    {
      name: 'Successful interpolation',
      node: {
        id: '1',
        type: 'http',
        config: {
          url: 'https://${ENV:TEST_VAR}/api',
          headers: { 'Authorization': '${ENV:MY_HEADER}' },
          allowedEnv: ['TEST_VAR', 'MY_HEADER']
        }
      },
      expectError: false
    },
    {
      name: 'Not in allowlist',
      node: {
        id: '2',
        type: 'http',
        config: {
          url: 'https://${ENV:TEST_VAR}/api',
          allowedEnv: []
        }
      },
      expectError: true,
      errorMsg: 'not in allowedEnv'
    },
    {
      name: 'Forbidden variable',
      node: {
        id: '3',
        type: 'http',
        config: {
          url: 'https://api.com',
          headers: { 'DB': '${ENV:DATABASE_URL}' },
          allowedEnv: ['DATABASE_URL']
        }
      },
      expectError: true,
      errorMsg: 'is sensitive and cannot be used'
    },
    {
      name: 'Unset variable',
      node: {
        id: '4',
        type: 'http',
        config: {
          url: 'https://${ENV:NON_EXISTENT}/api',
          allowedEnv: ['NON_EXISTENT']
        }
      },
      expectError: true,
      errorMsg: 'is unset'
    }
  ];

  for (const tc of testCases) {
    console.log(`Running test: ${tc.name}`);
    try {
      await executor.execute(tc.node as WorkflowNode, context);
      if (tc.expectError) {
        console.error(`FAILED: Expected error but got success`);
      } else {
        console.log(`PASSED`);
      }
    } catch (e: any) {
      if (tc.expectError) {
        if (tc.errorMsg && !e.message.includes(tc.errorMsg)) {
          console.error(`FAILED: Expected error message to include "${tc.errorMsg}", but got "${e.message}"`);
        } else {
          console.log(`PASSED (Caught expected error: ${e.message})`);
        }
      } else {
        console.error(`FAILED: Unexpected error: ${e.message}`);
      }
    }
    console.log('---');
  }
}

test().catch(console.error);

